"use client";

import { CheckIcon, CircleXIcon, CopyIcon } from "lucide-react";
import * as React from "react";
import { cn } from "~/lib/utils";
import { IosBarButton } from "../ios-bar-button/ios-bar-button";
import { IosSegmentedControl } from "../ios-segmented-control/ios-segmented-control";

const PACKAGE_MANAGERS = ["bun", "npm", "pnpm", "yarn"] as const;
const STORAGE_KEY = "sabraman-ios-code-block-command-package-manager";
const COPY_STATE_RESET_MS = 1800;

export type PackageManager = (typeof PACKAGE_MANAGERS)[number];

type CopyState = "idle" | "done" | "error";

type PackageManagerCommands = Partial<Record<PackageManager, string>>;

export interface IosCodeBlockCommandProps
	extends React.HTMLAttributes<HTMLDivElement> {
	bun?: string;
	initialPackageManager?: PackageManager;
	npm?: string;
	onCopyError?: (error: Error) => void;
	onCopySuccess?: (data: {
		command: string;
		packageManager: PackageManager;
	}) => void;
	pnpm?: string;
	yarn?: string;
}

export function IosCodeBlockCommand({
	bun,
	className,
	initialPackageManager,
	npm,
	onCopyError,
	onCopySuccess,
	pnpm,
	style,
	yarn,
	...props
}: IosCodeBlockCommandProps) {
	const commands = React.useMemo<PackageManagerCommands>(
		() => ({
			bun,
			npm,
			pnpm,
			yarn,
		}),
		[bun, npm, pnpm, yarn],
	);

	const availablePackageManagers = React.useMemo(
		() =>
			PACKAGE_MANAGERS.filter((packageManager) =>
				Boolean(commands[packageManager]),
			),
		[commands],
	);

	const fallbackPackageManager =
		availablePackageManagers[0] ?? initialPackageManager ?? "bun";

	const [packageManager, setPackageManager] = React.useState<PackageManager>(
		fallbackPackageManager,
	);
	const [copyState, setCopyState] = React.useState<CopyState>("idle");

	React.useEffect(() => {
		try {
			const storedPackageManager = window.localStorage.getItem(STORAGE_KEY);

			if (
				storedPackageManager &&
				availablePackageManagers.includes(
					storedPackageManager as PackageManager,
				)
			) {
				setPackageManager(storedPackageManager as PackageManager);
				return;
			}
		} catch { }

		if (
			initialPackageManager &&
			availablePackageManagers.includes(initialPackageManager)
		) {
			setPackageManager(initialPackageManager);
			return;
		}

		setPackageManager(fallbackPackageManager);
	}, [availablePackageManagers, fallbackPackageManager, initialPackageManager]);

	React.useEffect(() => {
		try {
			window.localStorage.setItem(STORAGE_KEY, packageManager);
		} catch { }
	}, [packageManager]);

	React.useEffect(() => {
		if (copyState === "idle") {
			return;
		}

		const timeout = window.setTimeout(() => {
			setCopyState("idle");
		}, COPY_STATE_RESET_MS);

		return () => {
			window.clearTimeout(timeout);
		};
	}, [copyState]);

	if (!availablePackageManagers.length) {
		return null;
	}

	const activeCommand =
		commands[packageManager] ?? commands[fallbackPackageManager] ?? "";

	async function handleCopy() {
		if (!activeCommand) {
			return;
		}

		try {
			await navigator.clipboard.writeText(activeCommand);
			setCopyState("done");
			onCopySuccess?.({
				command: activeCommand,
				packageManager,
			});
		} catch (error) {
			const copyError =
				error instanceof Error
					? error
					: new Error("Failed to copy command to clipboard");
			setCopyState("error");
			onCopyError?.(copyError);
		}
	}

	return (
		<div
			className={cn(
				"relative overflow-hidden rounded-[18px] border-[rgba(0,0,0,0.6)] border-[rgba(255,255,255,0.55)] border-t border-b bg-[linear-gradient(180deg,#dbe3ec_0%,#a8b3c4_100%)] p-[5px] shadow-[0_24px_50px_rgba(0,0,0,0.35),inset_0_1px_0_rgba(255,255,255,0.95)]",
				className,
			)}
			style={{
				...style,
				fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
			}}
			{...props}
		>
			<div className="relative overflow-hidden rounded-[13px] border-[rgba(0,0,0,0.72)] border-[rgba(255,255,255,0.18)] border-t border-b bg-[linear-gradient(180deg,#5a667d_0%,#313a4d_100%)] shadow-[0_14px_28px_rgba(0,0,0,0.38),inset_0_1px_1px_rgba(255,255,255,0.16)]">
				<div
					aria-hidden="true"
					className="pointer-events-none absolute inset-x-0 top-0 h-1/2 bg-gradient-to-b from-white/8 to-transparent"
				/>

				<div className="relative flex items-center justify-between gap-3 border-black/35 border-b px-4 py-3 shadow-[0_1px_0_rgba(255,255,255,0.08)]">
					<div className="flex items-center gap-3">
						<div className="flex w-[20px] shrink-0 items-center text-[#dbeaff] [filter:drop-shadow(0px_-1px_0px_rgba(0,0,0,0.45))] [&_svg]:size-[18px]">
							<PackageManagerIcon packageManager={packageManager} />
						</div>

						<IosSegmentedControl
							className="shrink-0"
							items={availablePackageManagers.map((manager) => ({
								label: manager,
								value: manager,
							}))}
							onValueChange={(nextPackageManager) => {
								setPackageManager(nextPackageManager);
							}}
							value={packageManager}
						/>
					</div>

					<IosBarButton
						aria-label="Copy command"
						className="shrink-0"
						disabled={!activeCommand}
						icon={
							copyState === "done" ? (
								<CheckIcon strokeWidth={3} />
							) : copyState === "error" ? (
								<CircleXIcon />
							) : (
								<CopyIcon />
							)
						}
						layout="icon"
						onClick={handleCopy}
					/>
				</div>

				<div
					aria-labelledby={`ios-command-tab-${packageManager}`}
					className="relative overflow-hidden bg-[linear-gradient(180deg,#1e2633_0%,#0f1420_100%)] px-4 py-4"
					id={`ios-command-panel-${packageManager}`}
					role="tabpanel"
				>
					<div className="pointer-events-none absolute inset-x-0 top-0 h-10 bg-gradient-to-b from-white/[0.04] to-transparent" />
					<div
						aria-hidden="true"
						className="pointer-events-none absolute inset-0 opacity-[0.18]"
						style={{
							backgroundImage:
								"repeating-linear-gradient(180deg, rgba(255,255,255,0.06) 0px, rgba(255,255,255,0.06) 1px, transparent 1px, transparent 3px)",
						}}
					/>
					<div className="pointer-events-none absolute inset-0 shadow-[inset_0_1px_0_rgba(255,255,255,0.05),inset_0_18px_30px_rgba(255,255,255,0.03),inset_0_-24px_40px_rgba(0,0,0,0.45)]" />

					<pre className="relative z-[1] overflow-x-auto">
						<code className="font-mono text-[#dbeaff] text-[13px] leading-[1.6]">
							<span className="select-none text-[#7fd7ff]">$ </span>
							<span className="whitespace-pre">{activeCommand}</span>
						</code>
					</pre>
				</div>
			</div>
		</div>
	);
}

