	}
}

export type ConvertNpmCommandResult = Record<PackageManager, string>;

export function convertNpmCommand(npmCommand: string): ConvertNpmCommandResult {
	if (npmCommand.startsWith("npm install")) {
		return {
			bun: npmCommand.replaceAll("npm install", "bun add"),
			npm: npmCommand,
			pnpm: npmCommand.replaceAll("npm install", "pnpm add"),
			yarn: npmCommand.replaceAll("npm install", "yarn add"),
		};
	}

	if (npmCommand.startsWith("npx create-")) {
		return {
			bun: npmCommand.replace("npx", "bunx --bun"),
			npm: npmCommand,
			pnpm: npmCommand.replace("npx create-", "pnpm create "),
			yarn: npmCommand.replace("npx create-", "yarn create "),
		};
	}

	if (npmCommand.startsWith("npm create")) {
		return {
			bun: npmCommand.replace("npm create", "bun create"),
			npm: npmCommand,
			pnpm: npmCommand.replace("npm create", "pnpm create"),
			yarn: npmCommand.replace("npm create", "yarn create"),
		};
	}

	if (npmCommand.startsWith("npx")) {
		return {
			bun: npmCommand.replace("npx", "bunx --bun"),
			npm: npmCommand,
			pnpm: npmCommand.replace("npx", "pnpm dlx"),
			yarn: npmCommand.replace("npx", "yarn"),
		};
	}

	if (npmCommand.startsWith("npm run")) {
		return {
			bun: npmCommand.replace("npm run", "bun"),
			npm: npmCommand,
			pnpm: npmCommand.replace("npm run", "pnpm"),
			yarn: npmCommand.replace("npm run", "yarn"),
		};
	}

	return {
		bun: npmCommand,
		npm: npmCommand,
		pnpm: npmCommand,
		yarn: npmCommand,
	};
}

"use client";

import * as React from "react";

import { cn } from "~/lib/utils";

type IosBarButtonVariant = "default" | "accent" | "destructive";
type IosBarButtonLayout = "text" | "icon" | "text-icon";

const BAR_BUTTON_BACKGROUND: Record<IosBarButtonVariant, string> = {
	accent:
		"linear-gradient(180deg, rgb(147, 181, 246) 0%, rgb(103, 144, 225) 33%, rgb(60, 113, 218) 67%, rgb(37, 98, 217) 100%)",
	default:
		"linear-gradient(180deg, rgb(162, 178, 201) 0%, rgb(121, 142, 172) 33%, rgb(80, 109, 148) 67%, rgb(64, 95, 138) 100%)",
	destructive:
		"linear-gradient(180deg, rgb(219, 139, 146) 0%, rgb(195, 98, 106) 33%, rgb(178, 48, 59) 67%, rgb(176, 26, 39) 100%)",
};

export interface IosBarButtonProps
	extends React.ButtonHTMLAttributes<HTMLButtonElement> {
	icon?: React.ReactNode;
	label?: string;
	layout?: IosBarButtonLayout;
	trailingIcon?: React.ReactNode;
	variant?: IosBarButtonVariant;
}

const IosBarButton = React.forwardRef<HTMLButtonElement, IosBarButtonProps>(
	(
		{
			className,
			icon,
			label,
			layout = icon ? (label ? "text-icon" : "icon") : "text",
			style,
			trailingIcon,
			type = "button",
			variant = "default",
			...props
		},
		ref,
	) => {
		return (
			<button
				ref={ref}
				className={cn(
					"relative inline-flex h-[29px] items-center justify-center overflow-hidden rounded-[5px] shadow-[0px_0.5px_0.5px_0px_rgba(255,255,255,0.4)] outline-none transition-transform duration-150 active:translate-y-px disabled:cursor-not-allowed disabled:opacity-50",
					layout === "text" && "min-w-[52px] px-[10px]",
					layout === "icon" && "min-w-[33px] px-[6px]",
					layout === "text-icon" &&
						"min-w-[50px] gap-[5px] pr-[15px] pl-[10px]",
					className,
				)}
				style={{
					...style,
					backgroundImage: BAR_BUTTON_BACKGROUND[variant],
					fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
				}}
				type={type}
				{...props}
			>
				{icon ? (
					<span className="relative z-[1] flex shrink-0 items-center justify-center text-white [filter:drop-shadow(0px_-1px_0px_rgba(0,0,0,0.4))] [&_svg]:size-[15px]">
						{icon}
					</span>
				) : null}
				{label ? (
					<span className="relative z-[1] min-w-[32px] whitespace-nowrap text-center font-bold text-[12px] text-white [text-shadow:0px_-1px_0px_rgba(0,0,0,0.4)]">
						{label}
					</span>
				) : null}
				{trailingIcon ? (
					<span className="relative z-[1] flex shrink-0 items-center justify-center text-white [filter:drop-shadow(0px_-1px_0px_rgba(0,0,0,0.4))] [&_svg]:size-[12px]">
						{trailingIcon}
					</span>
				) : null}
				<span
					aria-hidden="true"
					className="pointer-events-none absolute inset-0 rounded-[inherit] shadow-[inset_0px_0px_1px_0px_black,inset_0px_1px_0.5px_0px_rgba(0,0,0,0.4)]"
				/>
			</button>
		);
	},
);

IosBarButton.displayName = "IosBarButton";

export { IosBarButton };

"use client";

import * as React from "react";

import { cn } from "~/lib/utils";

const SEGMENT_ACTIVE_BACKGROUND =
	"linear-gradient(180deg, rgb(162, 178, 201) 0%, rgb(121, 142, 172) 33%, rgb(80, 109, 148) 67%, rgb(64, 95, 138) 100%)";
const SEGMENT_INACTIVE_BACKGROUND =
	"linear-gradient(180deg, rgb(177, 193, 213) 0%, rgb(145, 163, 187) 33%, rgb(114, 138, 169) 67%, rgb(96, 125, 160) 100%)";

export interface IosSegmentedControlItem<T extends string = string> {
	label: string;
	value: T;
	width?: number;
}

export interface IosSegmentedControlProps<T extends string = string>
	extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange"> {
	items: readonly IosSegmentedControlItem<T>[];
	onValueChange: (value: T) => void;
	value: T;
}

export function IosSegmentedControl<T extends string = string>({
	className,
	items,
	onValueChange,
	style,
	value,
	...props
}: IosSegmentedControlProps<T>) {
	return (
		<div
			className={cn(
				"relative inline-flex items-start overflow-hidden rounded-[5px] shadow-[0px_0.5px_0.5px_0px_rgba(255,255,255,0.4)]",
				className,
			)}
			role="tablist"
			style={{
				...style,
				fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
			}}
			{...props}
		>
			{items.map((item, index) => {
				const isActive = item.value === value;

				return (
					<React.Fragment key={item.value}>
						<button
							aria-selected={isActive}
							className="relative flex h-[29px] min-w-[54px] items-center justify-center px-[5px] transition-[filter] duration-150 hover:brightness-105"
							onClick={() => {
								onValueChange(item.value);
							}}
							role="tab"
							style={{
								backgroundImage: isActive
									? SEGMENT_ACTIVE_BACKGROUND
									: SEGMENT_INACTIVE_BACKGROUND,
								width: item.width,
							}}
							type="button"
						>
							<span className="relative z-[1] flex min-h-px min-w-px flex-1 flex-col justify-center text-center font-bold text-[12px] text-white [text-shadow:0px_-1px_0px_rgba(0,0,0,0.4)]">
								{item.label}
							</span>
						</button>
						{index < items.length - 1 ? (
							<span
								aria-hidden="true"
								className="w-px self-stretch bg-[rgba(0,0,0,0.25)]"
							/>
						) : null}
					</React.Fragment>
				);
			})}
			<span
				aria-hidden="true"
				className="pointer-events-none absolute inset-0 rounded-[inherit] shadow-[inset_0px_0px_1px_0px_black,inset_0px_1px_0.5px_0px_rgba(0,0,0,0.4)]"
			/>
		</div>
	);
}
